import{C as t,o as n,c as l,a5 as i,E as r}from"./chunks/framework.CW28V7p_.js";const c=JSON.parse('{"title":"6. Genesis ceremony","description":"","frontmatter":{},"headers":[],"relativePath":"module-1/6-genesis.md","filePath":"module-1/6-genesis.md","lastUpdated":1780937944000}'),o={name:"module-1/6-genesis.md"},g=Object.assign(o,{setup(p){const e={id:"m1-6-genesis",title:"🧠 Mini-check: Genesis",intro:"2 питання.",questions:[{type:"mcq",q:"Що defines unique cluster?",options:["Genesis hash","Initial validator set","Initial accounts state","Software version"],correct:[0,1,2],explanation:"Software version може evolve, genesis immutable. Module 1.6."},{type:"explain",q:"Як new community cluster (наприклад Alpenglow) запускається з genesis?",ideal:`New cluster bring-up process (community-coordinated):

1. **Plan**: organizers decide cluster purpose, expected operators, schedule.

2. **Solicit operators**: validators apply via form indicating їх pubkey + intent. Operators у "genesis set" otherwise self-stake at launch.

3. **Software version**: agreed-upon agave/Firedancer version. Optional cluster-specific fork patches.

4. **Genesis params**: organizer creates genesis using solana-genesis tool:
   - Initial validator pubkeys + initial stake amounts
   - Cluster parameters (slot duration, epoch length)
   - Initial features enabled
   - Output: genesis.tar.bz2 file

5. **Distribute genesis**: organizer publishes genesis hash + file URL. All operators verify hash matches expected.

6. **Coordinate start time**: organizer announces specific UTC time для все валідатори start simultaneously.

7. **All operators start** validator з same genesis at agreed time. Initially: small cluster, fast TX execution.

8. **Out-of-genesis operators** (як LumLabs Alpenglow case 2026-06) can join later by syncing з cluster + creating own vote account + getting stake delegation.

This ceremony similar для mainnet original launch 2020.`,explanation:"Module 1.6."}]};return(h,s)=>{const a=t("Quiz");return n(),l("div",null,[s[0]||(s[0]=i(`<h1 id="_6-genesis-ceremony" tabindex="-1">6. Genesis ceremony <a class="header-anchor" href="#_6-genesis-ceremony" aria-label="Permalink to &quot;6. Genesis ceremony&quot;">​</a></h1><h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><p><strong>Genesis</strong> = initial state of cluster (accounts, validators, parameters) at time-zero. <strong>Genesis hash</strong> uniquely identifies cluster. New cluster bring-up = community-coordinated process: organizer creates genesis, operators verify, all start simultaneously з same genesis.</p><h2 id="what-s-в-genesis" tabindex="-1">What&#39;s в genesis <a class="header-anchor" href="#what-s-в-genesis" aria-label="Permalink to &quot;What&#39;s в genesis&quot;">​</a></h2><p>Genesis file (<code>genesis.tar.bz2</code>) contains:</p><ol><li><strong>Initial accounts</strong>: pre-funded wallets, validators, system accounts</li><li><strong>Initial validator set</strong>: pubkeys + initial stake amounts</li><li><strong>Cluster parameters</strong>: <ul><li>Slot duration (typically 400ms)</li><li>Epoch length (typically 432,000 slots)</li><li>Inflation schedule</li><li>Fee schedule</li></ul></li><li><strong>Initial features enabled</strong>: which protocol features active from start</li><li><strong>Genesis hash</strong>: SHA-256 of the entire genesis (cluster identifier)</li></ol><p>After cluster starts, genesis immutable — referenced by все subsequent blocks через chain of parent hashes.</p><h2 id="genesis-creation" tabindex="-1">Genesis creation <a class="header-anchor" href="#genesis-creation" aria-label="Permalink to &quot;Genesis creation&quot;">​</a></h2><p>Cluster organizer uses <code>solana-genesis</code> tool:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">solana-genesis</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --bootstrap-validator</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">PUBKE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Y</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">        &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">VOTE_PUBKE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Y</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">        &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">STAKE_PUBKE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Y</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --bootstrap-validator-lamports</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 100000000</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --bootstrap-validator-stake-lamports</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 50000000</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --bootstrap-stake-authorized-pubkey</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">STAKE_AUTHORIT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Y</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --ledger</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /tmp/genesis-output</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --slots-per-epoch</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 432000</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --hashes-per-tick</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auto</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --ticks-per-slot</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 64</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --target-tick-duration</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 6250</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --cluster-type</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> development</span></span></code></pre></div><p>Many parameters. Each cluster organizer chooses thoughtfully.</p><p>Output:</p><ul><li><code>/tmp/genesis-output/genesis.bin</code> — binary genesis</li><li><code>/tmp/genesis-output/genesis.tar.bz2</code> — compressed для distribution</li></ul><h3 id="verify" tabindex="-1">Verify <a class="header-anchor" href="#verify" aria-label="Permalink to &quot;Verify&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sha256sum</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /tmp/genesis-output/genesis.bin</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Output = genesis hash, share з community</span></span></code></pre></div><p>All operators must verify they have identical hash.</p><h2 id="coordinated-launch-process" tabindex="-1">Coordinated launch process <a class="header-anchor" href="#coordinated-launch-process" aria-label="Permalink to &quot;Coordinated launch process&quot;">​</a></h2><h3 id="phase-1-planning" tabindex="-1">Phase 1: Planning <a class="header-anchor" href="#phase-1-planning" aria-label="Permalink to &quot;Phase 1: Planning&quot;">​</a></h3><p>Organizers (Anza for mainnet, community for Alpenglow):</p><ul><li>Determine purpose, scope, timeline</li><li>Recruit initial operators</li><li>Choose software stack</li><li>Set parameters</li></ul><h3 id="phase-2-operator-registration" tabindex="-1">Phase 2: Operator registration <a class="header-anchor" href="#phase-2-operator-registration" aria-label="Permalink to &quot;Phase 2: Operator registration&quot;">​</a></h3><p>Solicit interested validators:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Form fields:</span></span>
<span class="line"><span>- Operator name</span></span>
<span class="line"><span>- Validator identity pubkey</span></span>
<span class="line"><span>- Vote pubkey</span></span>
<span class="line"><span>- Stake pubkey</span></span>
<span class="line"><span>- Initial stake amount</span></span>
<span class="line"><span>- Contact info</span></span></code></pre></div><p>Approved operators included у genesis bootstrap set.</p><h3 id="phase-3-genesis-creation-distribution" tabindex="-1">Phase 3: Genesis creation + distribution <a class="header-anchor" href="#phase-3-genesis-creation-distribution" aria-label="Permalink to &quot;Phase 3: Genesis creation + distribution&quot;">​</a></h3><p>Organizer:</p><ul><li>Creates genesis з all operator pubkeys</li><li>Publishes genesis hash</li><li>Posts genesis file URL (typically GitHub release)</li></ul><p>Operators:</p><ul><li>Download genesis file</li><li>Verify hash matches expected</li><li>Place у local ledger directory</li></ul><h3 id="phase-4-start-coordination" tabindex="-1">Phase 4: Start coordination <a class="header-anchor" href="#phase-4-start-coordination" aria-label="Permalink to &quot;Phase 4: Start coordination&quot;">​</a></h3><p>Organizer announces:</p><ul><li>UTC start time</li><li>Entrypoint IPs</li><li>Software version</li></ul><p>All operators start validators within tight window (e.g., 5-min). Cluster begins producing blocks.</p><h3 id="phase-5-stabilization" tabindex="-1">Phase 5: Stabilization <a class="header-anchor" href="#phase-5-stabilization" aria-label="Permalink to &quot;Phase 5: Stabilization&quot;">​</a></h3><p>First 1-2 epochs:</p><ul><li>Verify cluster healthy (active stake, blocks producing)</li><li>Initial bugs/issues address</li><li>Cluster становить stable</li></ul><h2 id="alpenglow-case-study-jun-2026" tabindex="-1">Alpenglow case study (Jun 2026) <a class="header-anchor" href="#alpenglow-case-study-jun-2026" aria-label="Permalink to &quot;Alpenglow case study (Jun 2026)&quot;">​</a></h2><p>З твоєї cheatsheet §3:</p><ul><li><strong>Pre-restart</strong>: Anza Ashwin coordinates restart announcement у Discord</li><li><strong>Operators register</strong>: form для inclusion у new genesis</li><li><strong>Genesis created</strong>: новий genesis hash <code>F7m9FCZqve9pRmX3Ar4EqoZ1CUMFv8pZiN2gaELPWQtL</code></li><li><strong>In-genesis operators</strong>: pubkeys включені, ready to start</li><li><strong>Out-of-genesis operators</strong> (LumLabs missed form): join later</li></ul><p>LumLabs case (з Phase 0 cheatsheet):</p><ol><li>Did not fill form (overslept)</li><li>After cluster running, joined via: <ul><li>Wipe ledger</li><li>Build new agave version</li><li>Start з new genesis</li><li>Sync з cluster</li><li>Create vote account</li><li>Self-stake 2 SOL</li><li>Wait для Tim Garcia (organizer) to delegate community stake</li></ul></li></ol><h2 id="out-of-genesis-joining" tabindex="-1">Out-of-genesis joining <a class="header-anchor" href="#out-of-genesis-joining" aria-label="Permalink to &quot;Out-of-genesis joining&quot;">​</a></h2><p>Process when missed initial genesis:</p><ol><li><strong>Same software</strong> version as cluster (verify)</li><li><strong>Same genesis file</strong> (download from cluster&#39;s published source)</li><li><strong>Wipe own ledger</strong> (any stale data conflict)</li><li><strong>Start validator</strong> — fetches snapshot from cluster, catches up</li><li><strong>Create vote account</strong> з new BLS pubkey for Alpenglow</li><li><strong>Self-stake</strong> minimum required (cluster-specific)</li><li><strong>Wait для community delegation</strong> (з organizer&#39;a discretion)</li></ol><p>Out-of-genesis operators initially lower influence (less stake), но can grow over time.</p><h2 id="mini-quiz" tabindex="-1">Mini-quiz <a class="header-anchor" href="#mini-quiz" aria-label="Permalink to &quot;Mini-quiz&quot;">​</a></h2>`,46)),r(a,{data:e}),s[1]||(s[1]=i('<h2 id="glossary-additions" tabindex="-1">Glossary additions <a class="header-anchor" href="#glossary-additions" aria-label="Permalink to &quot;Glossary additions&quot;">​</a></h2><p><a href="/glossary#g"><code>Genesis ceremony</code></a>, <a href="/glossary#b"><code>Bootstrap validator</code></a>, <a href="/glossary#s"><code>solana-genesis</code></a>, <a href="/glossary#i"><code>In-genesis vs out-of-genesis</code></a></p><h2 id="external-refs" tabindex="-1">External refs <a class="header-anchor" href="#external-refs" aria-label="Permalink to &quot;External refs&quot;">​</a></h2><ul><li><a href="https://docs.anza.xyz/cli/solana-genesis" target="_blank" rel="noreferrer">solana-genesis tool</a></li></ul><hr><p><strong>Попередньо:</strong> <a href="/module-1/5-validator-status">← 5. Validator status</a></p>',6))])}}});export{c as __pageData,g as default};
